def read_local_context(base_dir: str, requested_path: str, file_map: dict[str, str]) -> str:
    def normalize_path(base: str, path: str) -> str:
        # Split the base and path into components
        base_parts = base.split('/')
        path_parts = path.split('/')

        # Initialize the normalized path with the base directory
        normalized_parts = base_parts[:]

        for part in path_parts:
            if part == '' or part == '.':
                # Skip empty or current directory parts
                continue
            elif part == '..':
                # Go up one directory level if possible
                if len(normalized_parts) > len(base_parts):
                    normalized_parts.pop()
            else:
                # Add the new directory or file to the path
                normalized_parts.append(part)

        # Join the normalized parts into a single path
        return '/'.join(normalized_parts)

    # Normalize the requested path
    normalized_path = normalize_path(base_dir, requested_path)

    # Check if the normalized path is within the base directory
    if not normalized_path.startswith(base_dir):
        return "Error: Path traversal detected or path is outside the base directory."

    # Check if the normalized path ends with '.txt'
    if not normalized_path.endswith('.txt'):
        return "Error: Only .txt files are allowed."

    # Attempt to read the file from the file_map
    if normalized_path in file_map:
        return file_map[normalized_path]
    else:
        return "Error: File not found."

